// Parse escrow expiring alert
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

const hoursUntilExpiry = d.cancelAfter 
  ? Math.round((new Date(d.cancelAfter).getTime() - Date.now()) / (1000 * 60 * 60))
  : 'unknown';

return [{
  json: {
    event: 'escrow.expiring',
    contractId: d.contractId,
    milestoneSeq: d.milestoneSeq,
    escrowSequence: d.escrowSequence,
    amount: d.amount,
    currency: d.currency,
    cancelAfter: d.cancelAfter,
    hoursUntilExpiry,
    creatorAddress: d.creatorAddress,
    marketplaceAddress: d.marketplaceAddress,
    timestamp: payload.timestamp
  }
}];

// Parse MCC minted event
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'mcc.minted',
    tokenId: d.tokenId,
    contractId: d.contractId,
    milestoneSeq: d.milestoneSeq,
    creatorId: d.creatorId,
    creatorAddress: d.creatorAddress,
    taxon: d.taxon || 1,
    metadataUri: d.metadataUri,
    timestamp: payload.timestamp
  }
}];

// URGENT: Escrow about to expire
const data = $input.first().json;

console.log(`[StudioLedger] ⚠️ ESCROW EXPIRING in ${data.hoursUntilExpiry} hours`);
console.log(`[StudioLedger] Contract: ${data.contractId}, Milestone: ${data.milestoneSeq}`);
console.log(`[StudioLedger] Amount: ${data.amount} ${data.currency}`);
console.log(`[StudioLedger] Cancel after: ${data.cancelAfter}`);
console.log(`[StudioLedger] Action: Both parties notified to complete or extend`);

return [{
  json: {
    ...data,
    notification: 'escrow_expiring_urgent',
    urgency: data.hoursUntilExpiry <= 24 ? 'critical' : 'warning',
    message: `Escrow expiring in ${data.hoursUntilExpiry}h — action required`
  }
}];

// MCC credential minted — notify creator
const data = $input.first().json;

console.log(`[StudioLedger] 🏆 MCC MINTED: ${data.tokenId}`);
console.log(`[StudioLedger] Creator: ${data.creatorId}`);
console.log(`[StudioLedger] Contract: ${data.contractId}, Milestone: ${data.milestoneSeq}`);
console.log(`[StudioLedger] Metadata: ${data.metadataUri}`);

return [{
  json: {
    ...data,
    notification: 'mcc_credential_minted',
    message: `New Minted Craft Credential issued — Token ID: ${data.tokenId}`
  }
}];
